// HUNTER SYNTHESIS — MICHA v10.8 — TOP 10 ROI ENGINE
const getAgent = (nodeName, listKey) => {
  try {
    const raw = $(nodeName).first().json;
    if (raw.choices) {
      const txt = raw.choices[0]?.message?.content || '';
      const m = txt.match(/\{[\s\S]*\}/); return m ? JSON.parse(m[0]) : {};
    }
    if (raw.candidates) {
      const txt = raw.candidates[0]?.content?.parts?.[0]?.text || '';
      const m = txt.match(/\{[\s\S]*\}/); return m ? JSON.parse(m[0]) : {};
    }
    return raw.error ? { error: raw.error } : raw;
  } catch(e) { return { error: e.message }; }
};

const U = getAgent('URIEL — Strategic Opportunity');
const C = getAgent('COLOSSUS — Technical Setups');
const H = getAgent('HANIEL — Intelligence Signals');
const R = getAgent('RAZIEL — Counter Thesis');

const agents_responded = [U,C,H,R].filter(a => !a.error && Object.keys(a).length > 1).length;

// Collect ALL tickers across all agents — market-wide net
const allTickers = new Set([
  ...(U.opportunities||[]).map(o=>o.ticker),
  ...(C.setups||[]).map(s=>s.ticker),
  ...(H.intelligence_signals||[]).map(i=>i.ticker)
].filter(Boolean));

// Score each ticker across agents — composite confidence
const scoredOps = [];
for (const tk of allTickers) {
  const u = (U.opportunities||[]).find(o=>o.ticker===tk);
  const c = (C.setups||[]).find(s=>s.ticker===tk);
  const h = (H.intelligence_signals||[]).find(i=>i.ticker===tk);
  const r = (R.counter_analyses||[]).find(a=>a.ticker===tk);
  const scores = [u?.confidence, c?.confidence, h?.confidence].filter(Boolean).map(Number);
  if (!scores.length) continue;
  const avg = Math.round(scores.reduce((a,b)=>a+b,0)/scores.length);
  const rs = Number(r?.raziel_score||50);
  const verdict = r?.verdict||'UNKNOWN';
  const ac = scores.length;
  let tier = 'PROBE';
  if (avg>=80 && rs>=70 && verdict==='CLEAR' && ac>=2) tier='PRIME';
  else if (avg>=65 && rs>=55 && verdict!=='ABORT') tier='STRONG';
  const ring = u?.ring || (['SGOV','BIL'].includes(tk)?'Ring1':['PSLV','IBIT'].includes(tk)?'Ring2':['FCX','PLTR'].includes(tk)?'Ring3':avg>=75?'Ring4':'Ring5');
  scoredOps.push({
    ticker:tk, signal_tier:tier, composite_confidence:avg,
    raziel_score:rs, raziel_verdict:verdict, ring, agent_count:ac,
    entry_thesis: u?.entry_thesis||c?.setup_type||h?.key_finding||'',
    catalyst: u?.catalyst||h?.signal_type||'',
