    stop_price: r?.stop_price||'',
    sources: [u?'URIEL':null,c?'COLOSSUS':null,h?'HANIEL':null,r?'RAZIEL':null].filter(Boolean)
  });
}

const order = {PRIME:0,STRONG:1,PROBE:2};
scoredOps.sort((a,b)=>(order[a.signal_tier]||3)-(order[b.signal_tier]||3)||b.composite_confidence-a.composite_confidence);
const top10 = scoredOps.slice(0,10);

