  if (!scores.length) continue;
  const avg = Math.round(scores.reduce((a,b)=>a+b,0)/scores.length);
  const rs = Number(r?.raziel_score||50);
  const verdict = r?.verdict||'UNKNOWN';
  const ac = scores.length;
