  if (avg>=80 && rs>=70 && verdict==='CLEAR' && ac>=2) tier='PRIME';
  else if (avg>=65 && rs>=55 && verdict!=='ABORT') tier='STRONG';
  const ring = u?.ring || (['SGOV','BIL'].includes(tk)?'Ring1':['PSLV','IBIT'].includes(tk)?'Ring2':['FCX','PLTR'].includes(tk)?'Ring3':avg>=75?'Ring4':'Ring5');
  scoredOps.push({
    ticker:tk, signal_tier:tier, composite_confidence:avg,
    raziel_score:rs, raziel_verdict:verdict, ring, agent_count:ac,
    entry_thesis: u?.entry_thesis||c?.setup_type||h?.key_finding||'',
    catalyst: u?.catalyst||h?.signal_type||'',
    sector: u?.sector||c?.sector||'',
    time_horizon: u?.time_horizon||c?.timeframe||'SWING',
